async function a(){const t=await fetch("/data/assortment_data.json",{cache:"no-store"});if(!t.ok)throw new Error(`Failed to load workspace data: ${t.status}`);return await t.json()}async function n(t){const s=await fetch("/api/assortment-decisions",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(t)});if(!s.ok){const o=await s.json().catch(()=>null);throw new Error((o==null?void 0:o.detail)??`Failed to save decision: ${s.status}`)}return s.json()}async function e(){const t=await fetch("/api/assortment-decisions",{cache:"no-store"});if(!t.ok)throw new Error(`Failed to load assortment decisions: ${t.status}`);return t.json()}export{e as f,a as l,n as s};
